```
#include "model.h"

namespace neon {
	Model::Model(const std::string &filename, Program* program) :
		m_program(program)
	{
		bool loaded_mesh = InitMeshes(filename);
		if(!loaded_mesh) {
			std::cout << "\nError: " << filename << " was not loaded" << std::endl;
		} else {
			std::cout << "\n" << filename << " loaded succesfully" << std::endl;
		}
	}

	Model::~Model() {}

	bool Model::InitMeshes(const std::string &filename) {
			Assimp::Importer importer;

			std::cout << "Assimp Loading: " << filename << std::endl;
			
			// Load the scene
			const aiScene* scene = importer.ReadFile( 
				filename,
				aiProcessPreset_TargetRealtime_Quality);
			
			// Check if there was errors with 
			if(!scene || scene->mFlags & AI_SCENE_FLAGS_INCOMPLETE || !scene->mRootNode)
			{
				std::cout << importer.GetErrorString() << std::endl;
				return false;
			}
			
			m_directory = filename.substr(0, filename.find_last_of('/'));

			AssimpProcessNode(scene->mRootNode, scene);
			
			return true;
	}

	void Model::AssimpProcessNode(aiNode *node, const aiScene *scene) {
		// std::cout << "Assimp Loading (mNumMeshes): " << node->mNumMeshes << std::endl;
		for(unsigned int i = 0; i < node->mNumMeshes; i++)
		{
			aiMesh* mesh = scene->mMeshes[node->mMeshes[i]];
			m_meshes.push_back(AssimpProcessMesh(mesh, scene));
		}
		// std::cout << "Assimp Loading (mNumChildren): " << node->mNumChildren << std::endl;
		for(unsigned int i = 0; i < node->mNumChildren; i++)
		{
			AssimpProcessNode(node->mChildren[i], scene);
		}
	}

	Mesh* Model::AssimpProcessMesh(aiMesh *mesh, const aiScene *scene) {
		std::vector<Vertex> vertices;
		std::vector<unsigned int> indices;
		std::vector<Texture> textures;
		// std::cout << "mesh->mNumVertices: " << mesh->mNumVertices << std::endl;
		for(unsigned int i = 0; i < mesh->mNumVertices; ++i)
		{
			Vertex vertex;
			// process vertex positions, normals and texture coordinates
			vertex.pos.x = mesh->mVertices[i].x;
			vertex.pos.y = mesh->mVertices[i].y;
			vertex.pos.z = mesh->mVertices[i].z;

			// UVs coordinates
			if(mesh->mTextureCoords[0]) // domes the mesh contain texture coordinates?
			{
				vertex.uv.x = mesh->mTextureCoords[0][i].x; 
				vertex.uv.y = mesh->mTextureCoords[0][i].y;
			}
			else {
				vertex.uv.x = 0.0f;
				vertex.uv.y = 0.0f;
			}

			// Normals
			vertex.normal.x = mesh->mNormals[i].x;
			vertex.normal.y = mesh->mNormals[i].y;
			vertex.normal.z = mesh->mNormals[i].z;

			//
			// TODO: Handle tangent and bittangent
			//
			vertices.push_back(vertex);
		}
		
		int count = 0;
		for(std::vector<Vertex>::iterator itr = vertices.begin(); itr < vertices.end(); ++itr) {
			std::cout << count << ": " << (*itr).pos.x << ", " << (*itr).pos.y << ", " << (*itr).pos.z  << std::endl;
			++count;
		}

		// process indices
		for(unsigned int i = 0; i < mesh->mNumFaces; i++)
		{
			aiFace face = mesh->mFaces[i];
			// std::cout << "face.mNumFaces: " << mesh->mNumFaces << std::endl;
			for(unsigned int j = 0; j < face.mNumIndices; j++) {
				// std::cout << "index: " << face.mIndices[j] << std::endl;
				indices.push_back(face.mIndices[j]);
			}
		}

		// for(std::vector<unsigned int>::iterator itr = indices.begin(); itr < indices.end(); ++itr) {
		// 	std::cout << (*itr) << std::endl;
		// }

		// process material
		if(mesh->mMaterialIndex >= 0)
		{
			// Handle materials
		}

		Mesh *n_mesh = new Mesh(m_program, vertices, indices);

		return n_mesh;
	}
}
```

