Right now the REST API does not have a merge endpoint. You should write your own apex classes that have the merging logic and functionality in them and expose them as webservices.
Then, from python you can call that webservice as described [here](https://github.com/simple-salesforce/simple-salesforce#using-apex).

For example:

Apex Class:
```
@RestResource(urlMapping='/MergeAccountsCustom/*')
global class MergeAccounts {

        @HttpPost
       //can't take map data types as arguments. Need to feed it a string and parse it as a map.
      webservice static String MergeAccs(List<String> idMap) {
         
         Map<Id,Id> primaryToSecondaryAcc = ParseIds(idMap);
         
         //do all your merging stuff here
         
         
         return String.valueOf(idMap);
         
         
      }
       
    //used wherever you're creating the string that is the map of id to id
    public static List<String> SetupIdsForParsing(Map<Id,Id> mapOfIdsForParsing){
        List<String> idsForParsing = new List<String>();
        for(Id idKey :mapOfIdsForParsing.keySet()){
            String idValue = mapOfIdsForParsing.get(idKey);
            String idForParsing = idKey +','+idValue;
            idsForParsing.add(idForParsing);
        }
        return idsForParsing;
    }
    
    public static Map<Id,Id> ParseIds(List<String> unParsedIdsList){
        Map<Id,Id> parsedIds = new Map<Id,Id>();
        for(String unParsedIds :unParsedIdsList){
            Integer indexOfComma = unParsedIds.indexOf(','); //comma is inserted at source point as a separation of id's
            Id firstId = unParsedIds.substring(0,indexOfComma);
            Id secondId = unParsedIds.substring(indexOfComma+1,unParsedIds.length());
            parsedIds.put(firstId,secondId);
        }
        return parsedIds;
    }                

}
```
